sql:
SELECT name, launch_date
FROM candy_bars
WHERE launch_date >= '2020-01-01';

SELECT competitor_name
FROM competitors
WHERE market_share = (SELECT MAX(market_share) FROM competitors);

SELECT name, price_percent
FROM candy_bars
ORDER BY price_percent DESC;

SELECT headquarters, COUNT(*) AS competitor_count
FROM competitors
GROUP BY headquarters;

external_knowledge:
- "Titans of the industry" refers to competitors with a significant market presence;
- "Cast a shadow over more than two-thirds of the market" metaphorically describes having a market share greater than 67%;
- "Humble price tag" metaphorically refers to a price percentage less than 7%;
- "Claim victory in more than three-quarters of the cases" refers to a win percentage greater than 65%.

sql:
SELECT cb.name
FROM candy_bars cb
JOIN consumer_preferences cp ON cb.candy_bar_id = cp.candy_bar_id
WHERE cp.rating = (
    SELECT MAX(rating) FROM consumer_preferences
);

SELECT name
FROM candy_bars
WHERE price_percent = (SELECT MAX(price_percent) FROM candy_bars);

external_knowledge:
- "Market giants with more than 70% control over the confectionery world" refers to competitors with a market share greater than 70%;
- "Loved by the public with an average rating of 4.5 stars or more" means the candy bars have received high ratings;
- "Sail smoothly across different income seas" indicates that the candy bars are consumed and appreciated across various consumer income brackets;
- "Average price tags" refers to the average price percentage of the candy bars.

sql:
SELECT competitor_name, market_share
FROM competitors
WHERE competitor_id IN (SELECT DISTINCT competitor_id FROM candy_bars);
